parameters.jsCode:
var text = $input.item.json.choices?.[0]?.message?.content || "";
if (!text) { return [{ json: { categoria: "Otro", subcategorias: [], herramientas: [], palabras_clave: [], resumen: "", accion: "" } }]; }

var catMatch = text.match(/\*\*Categor[ií]a\*\*:?\s*(.*?)(?:\n|$)/i);
var subMatch = text.match(/\*\*Subcategor[ií]as\*\*:?\s*([\s\S]*?)(?=\n\*\*Herramienta|$)/i);
var toolMatch = text.match(/\*\*Herramientas? Mencion[ao]das?\*\*:?\s*([\s\S]*?)(?=\n\*\*Palabras|$)/i);
var keyMatch = text.match(/\*\*Palabras Clave\*\*:?\s*([\s\S]*?)(?=\n\*\*Resumen|$)/i);
var resMatch = text.match(/\*\*Resumen Detallado\*\*:?\s*([\s\S]*?)(?=\n\*\*Gu[ií]a|$)/i);
var accMatch = text.match(/\*\*Gu[ií]a Paso a Paso \/ Acci[oó]n\*\*:?\s*([\s\S]*?)$/i);

function cleanList(m) {
  if (!m) return [];
  return m[1].split('\n').map(function(l) { 
    return l.replace(/^[-\s*•\d.]+/, "").trim(); 
  }).filter(function(l) { return l.length > 0; });
}

return [{
  json: {
    categoria: catMatch ? catMatch[1].trim() : "Otro",
    subcategorias: cleanList(subMatch),
    herramientas: cleanList(toolMatch),
    palabras_clave: cleanList(keyMatch),
    resumen: resMatch ? resMatch[1].trim() : "",
    accion: accMatch ? accMatch[1].trim() : ""
  }
}];

